use rand::Rng; // Import the Rng trait

fn main() {
    // Create a random number generator for the current thread
    let mut rng = rand::thread_rng();

    // Generate a random integer within a range [min, max] (inclusive)
    let min_val: i32 = 1;
    let max_val: i32 = 100;
    let random_int: i32 = rng.gen_range(min_val..=max_val); // Use ..= for inclusive range
    println!("Random integer ({}-{}): {}", min_val, max_val, random_int);

    // Generate a random float between 0.0 (inclusive) and 1.0 (exclusive)
    let random_f64: f64 = rng.gen(); // Type inference works here, or specify f64
    println!("Random float [0.0, 1.0): {}", random_f64);

    // Generate a random float within a specific range [min, max)
    let float_min = 10.0;
    let float_max = 20.0;
    let random_float_range: f64 = rng.gen_range(float_min..float_max); // Use .. for exclusive upper bound
    println!("Random float [{}..{}): {}", float_min, float_max, random_float_range);

    // Generate a random boolean
    let random_bool: bool = rng.gen();
    println!("Random boolean: {}", random_bool);
}

