fn reverse_string(s: &str) -> String {
    // Rust strings are UTF-8. Reversing bytes is incorrect for multi-byte characters.
    // This method reverses Unicode Scalar Values (characters like 'e' or 'é').
    // It might still visually break grapheme clusters (like "e\u{301}"). // Escaped \u
    // For true grapheme cluster reversal, use the 'unicode-segmentation' crate.
    s.chars().rev().collect::<String>()
}

fn main() {
    let original = "Hello World";
    let reversed = reverse_string(original);
    println!("Original: {}", original);
    println!("Reversed: {}", reversed);

    let unicode_string = "你好 Rust"; // Mixed ASCII and UTF-8
    let reversed_unicode = reverse_string(unicode_string);
    println!("Original UTF-8: {}", unicode_string);
    println!("Reversed UTF-8: {}", reversed_unicode); // Should be "tsuR 好你"
}

