// Function to generate the first n Fibonacci numbers iteratively
// Returns a Vec<u64>. Handles numbers up to u64::MAX.
fn generate_fibonacci(n: usize) -> Vec<u64> {
    if n == 0 {
        return Vec::new(); // Return empty vector for 0 terms
    }

    let mut sequence: Vec<u64> = Vec::with_capacity(n);
    let mut a: u64 = 0;
    let mut b: u64 = 1;

    for i in 0..n {
        sequence.push(a);
        // Use checked_add for safe addition, returns None on overflow
        match a.checked_add(b) {
            Some(next) => {
                a = b;
                b = next;
            }
            None => {
                println!("\nWarning: Fibonacci sequence overflowed u64 at term {}!", i + 2); // Escaped \n
                break; // Stop adding terms
            }
        }
    }
    sequence
}

fn main() {
    let num_terms = 10;
    let fib_numbers = generate_fibonacci(num_terms);
    println!("Fibonacci Sequence (first {} terms):", num_terms);
    // Print Vec directly using Debug formatting
    println!("{:?}", fib_numbers);
    // Or print comma-separated
    // let formatted: Vec<String> = fib_numbers.iter().map(|x| x.to_string()).collect();
    // println!("{}", formatted.join(", "));

    // Example showing overflow check (u64 overflows after term 93)
    let large_n = 94;
    println!("\nAttempting Fibonacci Sequence (first {} terms):", large_n); // Escaped \n
    let large_fib = generate_fibonacci(large_n);
    println!("{:?}", large_fib); // Will print up to term 93
}

