// Calculates factorial iteratively using u64. Checks for overflow.
fn factorial_u64(n: u32) -> Option<u64> {
    if n == 0 {
        return Some(1);
    }
    if n > 20 { // Factorial(21) overflows u64
         println!("Warning: Input {} > 20 will overflow u64.", n);
         // Return None early, or let checked_mul handle it
    }

    let mut result: u64 = 1;
    for i in 1..=n {
        // Use checked_mul which returns None on overflow
        match result.checked_mul(i as u64) {
            Some(next_result) => result = next_result,
            None => {
                println!("Overflow detected calculating factorial for {}!", n);
                return None; // Return None to indicate overflow
            }
        }
    }
    Some(result)
}

