// Function to check if a number is prime
// Input is u64, adjust type if needed
fn is_prime(n: u64) -> bool {
    if n <= 1 { return false; } // Numbers <= 1 are not prime
    if n <= 3 { return true; }  // 2 and 3 are prime

    // Eliminate multiples of 2 and 3 early
    if n % 2 == 0 || n % 3 == 0 { return false; }

    // Check factors from 5 upwards, stepping by 6
    // Only need to check up to the integer square root of n
    let limit = (n as f64).sqrt() as u64; // Calculate sqrt as float, then cast back

    let mut i: u64 = 5;
    while i <= limit {
        if n % i == 0 || n % (i + 2) == 0 {
            return false; // Found a factor
        }
        i += 6;
    }

    true // If no divisors found, it's prime
}


fn main() {
    let numbers_to_check: [u64; 11] = [0, 1, 2, 3, 4, 17, 25, 29, 97, 100, 104729];

    for &num in numbers_to_check.iter() { // Iterate over references
        if is_prime(num) {
            println!("{} is a prime number.", num);
        } else {
            println!("{} is not a prime number.", num);
        }
    }
    // Test negative - not possible with u64 input type
    // let negative_num: i64 = -5;
