use std::fs;
use std::path::Path;
use std::io::{self, BufRead, BufReader}; // For line-by-line reading

// Function to read entire file content into a String
// Returns Result<String, io::Error>
fn read_file_to_string(filepath: &str) -> io::Result<String> {
    println!("--- Reading entire file: {} ---", filepath);
    fs::read_to_string(filepath) // Simple helper function
}

// Function to read file line by line and print
// Returns Result<(), io::Error>
fn read_file_lines(filepath: &str) -> io::Result<()> {
    println!("--- Reading file line-by-line: {} ---", filepath);
    let file = fs::File::open(filepath)?; // Open file, ? propagates error
    let reader = BufReader::new(file); // Use a buffered reader for efficiency

    for line_result in reader.lines() {
        let line = line_result?; // Handle potential error reading each line
        println!("{}", line);
    }
    Ok(()) // Return Ok if successful
}

fn main() {
    let filename = "example_rust.txt";
    let filepath = Path::new(filename);

    // Create the example file first if it doesn't exist
    if !filepath.exists() {
        println!("Creating example file: {}", filename);
        // Use fs::write for simple creation/overwrite
        let content = "Line 1 from Rust.\\nLine 2 with UTF-8: 你好\\nLine 3."; // Escaped \n
        match fs::write(filepath, content) {
            Ok(_) => println!("Example file created."),
            Err(e) => {
                eprintln!("Error creating example file: {}", e);
                return; // Stop if creation fails
            }
        }
    }
    println!(""); // Blank line

    // --- Read using read_to_string ---
    match read_file_to_string(filename) {
        Ok(content) => {
            println!("Content (read_to_string):");
            println!("---");
            println!("{}", content);
            println!("---");
        }
        Err(e) => eprintln!("Error reading file to string: {}", e),
    }

    println!(""); // Blank line

    // --- Read using line iterator ---
    match read_file_lines(filename) {
        Ok(_) => println!("Finished reading lines."),
        Err(e) => eprintln!("Error reading file lines: {}", e),
    }

     // --- Test non-existent file ---
     println!(""); // Blank line
