use std::fs::{self, File, OpenOptions};
use std::io::{self, Write};
use std::path::Path;

// Function to write a string, overwriting the file
fn write_string_overwrite(filepath: &str, content: &str) -> io::Result<()> {
    println!("--- Writing (overwrite): {} ---", filepath);
    // fs::write is a convenience function that opens/writes/closes
    fs::write(filepath, content)
}

// Function to append a string to a file
fn append_string(filepath: &str, content_to_append: &str) -> io::Result<()> {
    println!("--- Appending to: {} ---", filepath);
    // Use OpenOptions to specify append mode and create if not exists
    let mut file = OpenOptions::new()
        .append(true)    // Enable append mode
        .create(true)    // Create the file if it doesn't exist
        .open(filepath)?; // Open the file

    // write_all attempts to write the entire buffer
    file.write_all(content_to_append.as_bytes())?;
    // file.flush()?; // Ensure data is written to OS (optional here as file closes soon)
    Ok(())
}

fn main() {
    let filename = "output_rust.txt";
    let initial_content = "Line 1 written by Rust.\\nLine 2 using fs::write.\\n"; // Escaped \n
    let append_content = "\\n-- Appended Content --\\nThis was appended.\\n"; // Escaped \n

    // --- Overwrite ---
    match write_string_overwrite(filename, initial_content) {
        Ok(_) => println!("Initial write successful."),
        Err(e) => eprintln!("Error during initial write: {}", e),
    }

    println!(""); // Blank line

    // --- Append ---
    match append_string(filename, append_content) {
        Ok(_) => println!("Append successful."),
        Err(e) => eprintln!("Error during append: {}", e),
    }

    println!("\nCheck content of '{}'", filename); // Escaped \n
}

