// Add `chrono = "0.4"` to Cargo.toml
use chrono::prelude::*; // Import common traits and types

fn main() {
    // --- Using Chrono crate --- Recommended ---

    // 1. Get current date and time in Local timezone
    let local_now: DateTime<Local> = Local::now();
    println!("Current Local DateTime: {}", local_now);
    // Debug format: println!("Debug Local: {:?}", local_now);

    // 2. Get current date and time in UTC
    let utc_now: DateTime<Utc> = Utc::now();
    println!("Current UTC DateTime: {}", utc_now);

    // 3. Get current date only (Local)
    // let today: Date<Local> = Local::today(); // Deprecated, use local_now.date()
    let today_new: NaiveDate = local_now.date_naive(); // Or timezone aware: local_now.date()
    println!("Current Local Date (NaiveDate): {}", today_new);
    // println!("Current Local Date (Date<Local>): {}", today); // If using older chrono

    // 4. Get current time only (Local)
    let current_time: NaiveTime = local_now.time();
    println!("Current Local Time (NaiveTime): {}", current_time);

    // 5. Formatting date/time objects into strings
    //    Uses strftime format codes: https://docs.rs/chrono/latest/chrono/format/strftime/index.html
    //    %Y-%m-%d %H:%M:%S is common
    //    %A, %B %d, %Y is readable
    //    %a, %b %e, %Y is shorter readable
    //    %+, %c are locale-dependent formats

    let formatted_ymdhms = local_now.format("%Y-%m-%d %H:%M:%S").to_string();
    println!("Formatted (YYYY-MM-DD HH:MM:SS): {}", formatted_ymdhms);

    let formatted_readable = local_now.format("%A, %B %d, %Y at %I:%M:%S %p %Z").to_string();
    println!("Formatted (Readable): {}", formatted_readable);

    // ISO 8601 / RFC 3339 format
    let formatted_rfc3339 = local_now.to_rfc3339_opts(SecondsFormat::Millis, true); // With UTC offset Z
    let formatted_rfc3339_utc = utc_now.to_rfc3339_opts(SecondsFormat::Millis, true);
    println!("Formatted (RFC3339 Local): {}", formatted_rfc3339);
    println!("Formatted (RFC3339 UTC):   {}", formatted_rfc3339_utc);


    // 6. Parsing strings into date/time objects
    let date_str = "2025-07-15 14:30:00";
    let format_str = "%Y-%m-%d %H:%M:%S";
    match NaiveDateTime::parse_from_str(date_str, format_str) {
        Ok(parsed_naive) => {
            // We parsed a naive date time, assume local zone or specify one
            let local_dt = Local.from_local_datetime(&parsed_naive).unwrap(); // Add timezone info
            println!("Parsed Naive '{}' as Local: {}", date_str, local_dt);
        }
        Err(e) => eprintln!("Error parsing date string '{}': {}", date_str, e),
    }

    // Parsing RFC 3339
    let rfc_str = "2025-03-30T18:00:00+00:00"; // Example with offset
    match DateTime::parse_from_rfc3339(rfc_str) {
        Ok(parsed_rfc) => println!("Parsed RFC3339 '{}' as: {}", rfc_str, parsed_rfc),
        Err(e) => eprintln!("Error parsing RFC3339 string '{}': {}", rfc_str, e),
    }

    // 7. Getting Unix Timestamp (seconds since epoch UTC)
    let timestamp_secs: i64 = local_now.timestamp();
    let timestamp_millis: i64 = local_now.timestamp_millis();
    let timestamp_nanos: i64 = local_now.timestamp_nanos_opt().unwrap_or(0); // Handle potential failure if out of range

    println!("Timestamp (seconds): {}", timestamp_secs);
    println!("Timestamp (millis):  {}", timestamp_millis);
    // println!("Timestamp (nanos):   {}", timestamp_nanos); // May be very large

}

