fn main() {
    let numbers: [i32; 9] = [10, 5, 42, 17, 8, 99, 32, -5, 0];
    let floats: [f64; 5] = [10.1, 5.5, 42.0, 17.3, 8.9];
    let empty_array: [i32; 0] = []; // Zero-sized array

    println!("Integer array: {:?}", numbers);
    println!("Float array: {:?}", floats);

    // Use the .iter().max() method on slices/arrays/vectors
    // It returns an Option<&T>, which is Some(max_value) or None if empty.

    // --- For Integers ---
    match numbers.iter().max() {
        Some(max_val) => println!("Max integer value: {}", max_val), // max_val is a &i32 here
        None => println!("Integer array is empty, no maximum."),
    }

    // --- For Floats ---
    // Note: max() for floats requires values to be comparable (not NaN)
    // Use partial_cmp for floats if NaN might be present, or filter them first.
    // Simple max() assumes no NaNs for brevity.
     match floats.iter().copied().max_by(|a, b| a.partial_cmp(b).unwrap()) {
         Some(max_val) => println!("Max float value: {}", max_val), // max_val is f64
         None => println!("Float array is empty, no maximum."),
     }
     // Alternative simpler for non-NaN floats:
     // match floats.iter().max_by(|a, b| a.total_cmp(b)) { ... }

    // --- For Empty Array ---
    println!("\nChecking empty array:"); // Escaped \n
    match empty_array.iter().max() {
        Some(max_val) => println!("Max value (empty): {} (Should not happen)", max_val),
        None => println!("Correctly found no maximum in empty array."),
    }

    // If you have a Vec<T> instead of an array, it works the same way:
    let number_vec = vec![1, 5, 2, 8, 3];
    match number_vec.iter().max() {
         Some(max_val) => println!("\nMax value in Vec: {}", max_val), // Escaped \n
         None => println!("Vec is empty."),
    }

}
